label("5",(0,3.5),W);
label("4",(2,6),N);
label("7",(7.5,6),N);
label("3",(11,1.5),E);
label("3",(11,4.5),E);
label("4",(5,1.5),N);
label("6",(3,0),N);
label("15",(8.5,1),N);
label("20",(2,3),N);
label("21",(7.5,4),N);

[/asy]

